def parse_duration(s: str) -> int:
    """Parse a duration string into total seconds.

    Args:
        s: A string representing duration (e.g., '2h30m', '45m', '1h', '90s').

    Returns:
        Total duration in seconds.

    Raises:
        ValueError: If the input string is invalid.
    """
    if not s:
        raise ValueError("Empty duration string")

    total = 0
    num_str = ''
    for char in s:
        if char.isdigit():
            num_str += char
        elif char in ('h', 'm', 's'):
            if not num_str:
                raise ValueError(f"Invalid duration format: {s}")
            num = int(num_str)
            if char == 'h':
                total += num * 3600
            elif char == 'm':
                total += num * 60
            elif char == 's':
                total += num
            num_str = ''
        else:
            raise ValueError(f"Invalid character in duration: {char}")

    if num_str:
        raise ValueError(f"Invalid duration format: {s}")

    return total
